import { extractString } from '../../../utils/extract.js';
import { handleError } from '../../error.js';
export const createServerPreUploadLevelResultRouteHandler = (levelResult) => async ({ req, res, next, localize, ctx }) => {
    if (!levelResult.preUploadHandler) {
        res.status(404).end();
        return;
    }
    const key = extractString(req.headers['sonolus-upload-key']);
    if (key === undefined) {
        res.status(400).end();
        return;
    }
    const response = await levelResult.preUploadHandler({ ...ctx, key });
    if (handleError(response, res, localize))
        return;
    next();
};
